SELECT name, grade, class_name as className, class_number as classNumber, total_point as totalPoint
FROM students
WHERE student_id = #{studentId} AND password = #{password}

SELECT SUM(CASE WHEN content='매수' THEN amount ELSE -amount END) AS amount
FROM orders
WHERE student_id = #{studentId}
AND stock_no = #{stockNo}
AND state='체결'

SELECT total_point
FROM students
WHERE student_id = #{studentId}

SELECT order_no, CONTENT, PRICE, AMOUNT, ORDER_DATE, STATE
FROM ORDERS
WHERE STUDENT_ID = #{studentId}
AND STOCK_NO = #{stockNo}
AND state ='대기'
ORDER BY ORDER_DATE ASC

SELECT publication_balance, publication_price
FROM stocks
WHERE stock_no = #{stockNo}

SELECT order_no, content, price, amount, state, order_date, student_id, stock_no
FROM orders
WHERE order_no =
(SELECT order_no
FROM (SELECT order_no
FROM orders
WHERE stock_no = #{stockNo}
AND state = '대기'
AND content = #{content}
AND price = #{price}
AND amount = #{amount}
AND student_id != #{studentId}
ORDER BY order_date ASC)
WHERE ROWNUM = 1)
FOR UPDATE

SELECT order_no
FROM orders
WHERE content = #{content}
AND student_id = #{studentId}
AND stock_no = #{stockNo}
AND state = #{state}
AND amount = #{amount}
AND price = #{price} ORDER BY order_date DESC
